// Get all items from Merge
const allItems = $input.all();

// Extract data
const extractItem = allItems[0]?.json || {};
const titleData = extractItem.data || extractItem;

// Analysis
const analysisItem = allItems[1]?.json || {};
const riskAnalysis = analysisItem.markdown || analysisItem.answer || analysisItem.text || 'No analysis generated';

// Trigger data
const triggerData = $('New Title Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Format grantors
const grantors = titleData.grantor || [];
const grantorNames = grantors.map(g => g.name).join(', ') || 'Unknown';

// Format grantees
const grantees = titleData.grantee || [];
const granteeNames = grantees.map(g => `${g.name}${g.vestingType ? ' (' + g.vestingType + ')' : ''}`).join(', ') || 'Unknown';

// Property description
const prop = titleData.propertyDescription || {};
const propertyAddress = [prop.streetAddress, prop.city, prop.state].filter(Boolean).join(', ') || 'See legal description';

// Recording info
const rec = titleData.recordingInfo || {};
const recordingInfo = `${rec.recordingDate || 'N/A'} - Doc #${rec.documentNumber || 'N/A'}`;

// Format liens
const liens = titleData.liens || [];
const lienSummary = liens.map(l => `${l.type}: $${l.amount || 'N/A'} (${l.holder || 'Unknown'})`).join('; ') || 'None found';
const totalLienAmount = liens.reduce((sum, l) => sum + (l.amount || 0), 0);

// Format easements
const easements = titleData.easements || [];
const easementSummary = easements.map(e => `${e.type}: ${e.description || 'N/A'}`).join('; ') || 'None';

// Format encumbrances
const encumbrances = titleData.encumbrances || [];
const encumbranceSummary = encumbrances.join('; ') || 'None';

// Format exceptions
const exceptions = titleData.exceptions || [];
const exceptionSummary = exceptions.join('; ') || 'None';

// Count risks from analysis
const analysisLower = riskAnalysis.toLowerCase();
const criticalCount = (analysisLower.match(/critical/g) || []).length;
const highCount = (analysisLower.match(/high/g) || []).length;
const mediumCount = (analysisLower.match(/medium/g) || []).length;

// Determine risk score
let riskScore = 85;
if (criticalCount > 0) riskScore = 30;
else if (highCount > 0) riskScore = 50;
else if (mediumCount > 0) riskScore = 70;
else if (liens.length > 0) riskScore = 75;

// Risk level
let riskLevel = 'Low';
if (riskScore < 50) riskLevel = 'High';
else if (riskScore < 70) riskLevel = 'Medium';

// Insurability
let insurability = 'Insurable';
if (criticalCount > 0) insurability = 'Not Insurable - Critical Issues';
else if (highCount > 0) insurability = 'Conditional - Requires Cure';
else if (liens.length > 3) insurability = 'Conditional - Multiple Liens';

return [{
  json: {
    documentType: titleData.documentType || 'Unknown',
    grantorNames: grantorNames,
    granteeNames: granteeNames,
    propertyAddress: propertyAddress,
    legalDescription: prop.legalDescription || 'N/A',
    county: prop.county || 'N/A',
    state: prop.state || 'N/A',
    parcelNumber: prop.parcelNumber || 'N/A',
    recordingDate: rec.recordingDate || 'N/A',
    recordingInfo: recordingInfo,
    consideration: titleData.consideration || 0,
    lienCount: liens.length,
    lienSummary: lienSummary,
    totalLienAmount: totalLienAmount,
    easementCount: easements.length,
    easementSummary: easementSummary,
    encumbranceSummary: encumbranceSummary,
    exceptionSummary: exceptionSummary,
    riskScore: riskScore,
    riskLevel: riskLevel,
    criticalIssues: criticalCount,
    highIssues: highCount,
    mediumIssues: mediumCount,
    insurability: insurability,
    riskAnalysis: riskAnalysis,
    fileName: fileName,
    fileId: fileId,
    processedAt: new Date().toISOString()
  }
}];

